18158   };
18159   auto TryAppendToPostponedInsts = [&](Instruction *FutureSeed) {
18160     if (TryOperandsAsNewSeeds && FutureSeed == Root) {
18161       FutureSeed = getNonPhiOperand(Root, P);
18162       if (!FutureSeed)
