18172   while (!Stack.empty()) {
18173     Instruction *Inst;
18174     unsigned Level;
18175     std::tie(Inst, Level) = Stack.front();
18176     Stack.pop();
18177     // Do not try to analyze instruction that has already been vectorized.
18178     // This may happen when we vectorize instruction operands on a previous
18179     // iteration while stack was populated before that happened.
18180     if (R.isDeleted(Inst))
18181       continue;
