18183       Res = true;
18184       if (auto *I = dyn_cast<Instruction>(VectorizedV)) {
18185         // Try to find another reduction.
18186         Stack.emplace(I, Level);
18187         continue;
18188       }
18189       if (R.isDeleted(Inst))
18190         continue;
18191     } else {
18192       // We could not vectorize `Inst` so try to use it as a future seed.
18193       if (!TryAppendToPostponedInsts(Inst)) {
18194         assert(Stack.empty() && "Expected empty stack");
18195         break;
18196       }
18197     }
18198 
18199     // Try to vectorize operands.
18200     // Continue analysis for the instruction from the same basic block only to
18201     // save compile time.
18202     if (++Level < RecursionMaxDepth)
